app.get('/api/vault/search', async (req) => {
  const q = (req.query.q || '').toLowerCase()
  if (!q) return { results: [] }
  const results = []
  function searchDir(dir, prefix = '') {
    try {
      const entries = readdirSync(dir, { withFileTypes: true })
      for (const e of entries) {
        if (e.name.startsWith('.')) continue
        const rel = prefix ? prefix + '/' + e.name : e.name
        if (e.isDirectory()) { searchDir(join(dir, e.name), rel); continue }
        if (!e.name.endsWith('.md')) continue
        if (e.name.toLowerCase().includes(q)) { results.push({ path: rel, match: 'filename' }); continue }
        try {
          const content = readFileSync(join(dir, e.name), 'utf8')
          if (content.toLowerCase().includes(q)) {
            const idx = content.toLowerCase().indexOf(q)
            const snippet = content.slice(Math.max(0, idx - 40), idx + q.length + 40)
            results.push({ path: rel, match: 'content', snippet })
          }
        } catch {}
      }
    } catch {}
  }
  searchDir(VAULT_ROOT)
  return { results: results.slice(0, 50) }
})

// Graph data (links between notes)
app.get('/api/vault/graph', async () => {
  const nodes = []
  const links = []
  const noteMap = {}
  function scanDir(dir, prefix = '') {
    try {
      const entries = readdirSync(dir, { withFileTypes: true })
      for (const e of entries) {
        if (e.name.startsWith('.')) continue
        const rel = prefix ? prefix + '/' + e.name : e.name
        if (e.isDirectory()) { scanDir(join(dir, e.name), rel); continue }
        if (!e.name.endsWith('.md')) continue
        const id = rel.replace(/\.md$/, '')
        const name = e.name.replace(/\.md$/, '')
        nodes.push({ id, name, folder: prefix || 'root' })
        noteMap[name.toLowerCase()] = id
        try {
          const content = readFileSync(join(dir, e.name), 'utf8')
          // Find [[wikilinks]]
          const wikilinks = content.match(/\[\[([^\]]+)\]\]/g) || []
          for (const link of wikilinks) {
            const target = link.slice(2, -2).split('|')[0].trim()
            if (!noteMap[target.toLowerCase()]) noteMap[target.toLowerCase()] = target
            links.push({ source: id, target: target.toLowerCase() })
          }
          // Find tags
          const tags = content.match(/#[a-zA-Z][\w-]*/g) || []
          if (tags.length) nodes[nodes.length - 1].tags = [...new Set(tags)]
        } catch {}
      }
    } catch {}
  }
  scanDir(VAULT_ROOT)
  // Resolve link targets
  const resolvedLinks = links.map(l => ({
    source: l.source,
    target: noteMap[l.target] || l.target
  })).filter(l => nodes.some(n => n.id === l.target))
  return { nodes, links: resolvedLinks }
})

