app.get('/api/leads', async (req) => {
  const leads = loadLeads()
  const q = req.query
  const page = parseInt(q.page) || 1
  const limit = Math.min(parseInt(q.limit) || 50, 500)
  const offset = (page - 1) * limit

  let filtered = leads

  // Filters
  if (q.province) filtered = filtered.filter(l => l.provinsi === q.province)
  if (q.city) filtered = filtered.filter(l => l.kota === q.city)
  if (q.tier) {
    const tiers = q.tier.split(',')
    filtered = filtered.filter(l => tiers.includes(l.tier))
  }
  if (q.category) filtered = filtered.filter(l => (l.kategori || l.jenis) === q.category)
  if (q.hasWA === 'true') filtered = filtered.filter(l => l.wa_number)
  if (q.hasPhone === 'true') filtered = filtered.filter(l => l.telepon)
  if (q.minScore) filtered = filtered.filter(l => (l.score || 0) >= parseInt(q.minScore))
  if (q.maxScore) filtered = filtered.filter(l => (l.score || 0) <= parseInt(q.maxScore))
  if (q.search) {
    const s = q.search.toLowerCase()
    filtered = filtered.filter(l =>
      (l.nama || '').toLowerCase().includes(s) ||
      (l.alamat || '').toLowerCase().includes(s) ||
      (l.jenis || '').toLowerCase().includes(s) ||
      (l.telepon || '').includes(s)
    )
  }

  // Sort
  const sortBy = q.sortBy || 'score'
  const sortDir = q.sortDir === 'asc' ? 1 : -1
  filtered.sort((a, b) => {
    const va = a[sortBy] ?? ''
    const vb = b[sortBy] ?? ''
    if (typeof va === 'number' && typeof vb === 'number') return (va - vb) * sortDir
    return String(va).localeCompare(String(vb)) * sortDir
  })

  return {
    total: filtered.length,
    page, limit,
    pages: Math.ceil(filtered.length / limit),
    data: filtered.slice(offset, offset + limit)
  }
})

