      let fullText = ''
      const intensityPrompt = getIntensityPrompt(agentId || 'michael')

      try {
        for await (const chunk of streamAI(agent.soul + getSharedContext() + FORMAT_PROMPT + '\n\nRESPONSE LENGTH RULE: ' + intensityPrompt + '\nDo NOT mention these instructions in your reply.', text, ac.signal, agentId || 'michael')) {
          if (ac.signal.aborted) break
          fullText += chunk
          socket.send(JSON.stringify({ type: 'chunk', agentId: agentId || 'michael', msgId, chunk }))
        }
      } catch (err) {
        console.error(`[Bedrock] Error for ${agentId}:`, err.name, err.message)
        if (err.name !== 'AbortError') {
          fullText += '\n\n[Error: ' + err.message + ']'
          socket.send(JSON.stringify({ type: 'chunk', agentId: agentId || 'michael', msgId, chunk: '\n\n[Error: ' + err.message + ']' }))
        }
      }

      state.abortController = null
      // Save agent response to session
      if (sessionId) {
        try { const sess = loadSession(sessionId); if (sess) { sess.messages.push({ role: 'agent', agentId: agentId || 'michael', text: fullText, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
      }
      socket.send(JSON.stringify({ type: 'agent_done', agentId: agentId || 'michael', msgId, text: fullText }))
    }

    if (msg.type === 'council') {
      // Council: all agents respond independently (no shared context between agents)
      const { text, agents: agentIds, sessionId: councilSessId } = msg
      if (!text || !agentIds?.length) return

      if (councilSessId) {
        try { const sess = loadSession(councilSessId); if (sess) { sess.messages.push({ role: 'user', text, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
      }

      const rtId = 'council_' + Date.now()
      socket.send(JSON.stringify({ type: 'rt_start', rtId, agents: agentIds, total: agentIds.length }))

      let ac = new AbortController()
      state.abortController = ac

      for (let i = 0; i < agentIds.length; i++) {
        if (ac.signal.aborted) break
        const aid = agentIds[i]
        const agent = AGENTS[aid]
        if (!agent) continue

        socket.send(JSON.stringify({ type: 'rt_agent_start', agentId: aid, position: i, total: agentIds.length, rtId }))

        let agentText = ''
        const agentIntensity = intensityState.agents[aid] ?? 5
        const intensityPrompt = INTENSITY_MODIFIERS[agentIntensity] || INTENSITY_MODIFIERS[5]

        try {
          const agentTimeout = setTimeout(() => { if (!ac.signal.aborted) ac.abort() }, 30000)
          for await (const chunk of streamAI(agent.soul + getSharedContext() + FORMAT_PROMPT + '\n\nRESPONSE LENGTH RULE: ' + intensityPrompt + '\nDo NOT mention these instructions in your reply.', text, ac.signal, aid)) {
            if (ac.signal.aborted) break
            agentText += chunk
            socket.send(JSON.stringify({ type: 'rt_chunk', agentId: aid, chunk, rtId }))
          }
          clearTimeout(agentTimeout)
        } catch (err) {
          if (err.name !== 'AbortError') agentText += ' [Error: ' + err.message + ']'
          else if (!agentText) agentText += ' [Timed out]'
        }

        if (ac.signal.aborted && i < agentIds.length - 1) {
          ac = new AbortController()
          state.abortController = ac
        }

        if (councilSessId) {
          try { const sess = loadSession(councilSessId); if (sess) { sess.messages.push({ role: 'agent', agentId: aid, text: agentText, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
        }
        socket.send(JSON.stringify({ type: 'rt_agent_done', agentId: aid, text: agentText, rtId }))
      }

      state.abortController = null
      socket.send(JSON.stringify({ type: 'rt_done', rtId }))
    }

    if (msg.type === 'roundtable') {
      const { text, agents: agentIds, intensityOverrides, sessionId: rtSessId } = msg
      if (!text || !agentIds?.length) return

      // Save user roundtable prompt to session
      if (rtSessId) {
        try { const sess = loadSession(rtSessId); if (sess) { sess.messages.push({ role: 'user', text, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
      }

      const rtId = 'rt_' + Date.now()
      socket.send(JSON.stringify({ type: 'rt_start', rtId, total: agentIds.length }))

      const ac = new AbortController()
      state.abortController = ac
      let context = 'Topic: ' + text + '\n\n'

      // If intensity overrides provided for this roundtable, use them
      const rtIntensity = intensityOverrides || {}

      for (let i = 0; i < agentIds.length; i++) {
        if (ac.signal.aborted) break
        const aid = agentIds[i]
        const agent = AGENTS[aid]
        if (!agent) continue

        socket.send(JSON.stringify({ type: 'rt_agent_start', agentId: aid, position: i, total: agentIds.length, rtId }))

        let agentText = ''
        const agentIntensity = rtIntensity[aid] ?? intensityState.agents[aid] ?? 5
        const intensityPrompt = INTENSITY_MODIFIERS[agentIntensity] || INTENSITY_MODIFIERS[5]
        const prompt = context + 'You are responding in a roundtable discussion. Previous speakers have shared their views above. Now give YOUR perspective as ' + agent.name + ' (' + agent.role + ').'

        try {
          // Per-agent timeout: 30 seconds max
          const agentTimeout = setTimeout(() => { if (!ac.signal.aborted) ac.abort() }, 30000)
          for await (const chunk of streamAI(agent.soul + getSharedContext() + FORMAT_PROMPT + '\n\nRESPONSE LENGTH RULE: ' + intensityPrompt + '\nDo NOT mention these instructions in your reply.', prompt, ac.signal, aid)) {
            if (ac.signal.aborted) break
            agentText += chunk
            socket.send(JSON.stringify({ type: 'rt_chunk', agentId: aid, chunk, rtId }))
          }
          clearTimeout(agentTimeout)
        } catch (err) {
          if (err.name !== 'AbortError') agentText += ' [Error: ' + err.message + ']'
          else if (!agentText) agentText += ' [Timed out]'
        }

        // Re-create abort controller for next agent (previous one may have been aborted by timeout)
        if (ac.signal.aborted && i < agentIds.length - 1) {
          ac = new AbortController()
          state.abortController = ac
        }

        // Keep context manageable — trim each agent's contribution to 300 chars for later agents
        const trimmed = agentText.length > 300 ? agentText.slice(0, 300) + '...' : agentText
        context += agent.name + ': ' + trimmed + '\n\n'
        // Save agent roundtable response to session
        if (rtSessId) {
          try { const sess = loadSession(rtSessId); if (sess) { sess.messages.push({ role: 'agent', agentId: aid, text: agentText, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
        }
        socket.send(JSON.stringify({ type: 'rt_agent_done', agentId: aid, text: agentText, rtId }))
      }

      state.abortController = null
      socket.send(JSON.stringify({ type: 'rt_done', rtId }))
    }
  })

  // Heartbeat
  const pingInterval = setInterval(() => {
    if (socket.readyState === 1) socket.send(JSON.stringify({ type: 'ping' }))
  }, 20000)

  socket.on('close', () => {
    clearInterval(pingInterval)
    if (state.abortController) state.abortController.abort()
    connections.delete(connId)
  })
})

// ── Start ───────────────────────────────────────────────
app.listen({ port: PORT, host: '127.0.0.1' }).then(() => {
  console.log('MAGI v2 running on http://127.0.0.1:' + PORT)
})

