**Backend changes needed:**
Add report generation and storage:
```javascript
const REPORTS_FILE = join(__dirname, 'data', 'reports.json')

function loadReports() { 
  try { if (existsSync(REPORTS_FILE)) return JSON.parse(readFileSync(REPORTS_FILE, 'utf8')) } catch {} 
  return { reports: [], nextId: 1 } 
}
function saveReports(d) { d.reports = d.reports.slice(-52); writeFileSync(REPORTS_FILE, JSON.stringify(d, null, 2)) }

// POST /api/reports/generate — generate a report snapshot
app.post('/api/reports/generate', async (req) => {
  const { type, dateRange } = req.body || {}
  const analytics = loadAnalytics()
  const tasks = loadTasks()
  const pipeline = loadPipeline()
  const contacts = loadContacts()

  const now = new Date()
  const weekAgo = new Date(now - 7 * 86400000)
  const weekKey = weekAgo.toISOString().slice(0,10) + '_to_' + now.toISOString().slice(0,10)

  // Collect 7-day stats
  let weekRequests = 0, weekTokensIn = 0, weekTokensOut = 0, weekCost = 0
  const agentBreakdown = {}
  for (let i = 0; i < 7; i++) {
    const d = new Date(now - i * 86400000).toISOString().slice(0,10)
    const day = analytics.daily[d]
    if (!day) continue
    weekRequests += day.requests || 0
    weekTokensIn += day.inputTokens || 0
    weekTokensOut += day.outputTokens || 0
    weekCost += day.cost || 0
    for (const [aid, stats] of Object.entries(day.agents || {})) {
      if (!agentBreakdown[aid]) agentBreakdown[aid] = { requests: 0, tokens: 0, cost: 0 }
      agentBreakdown[aid].requests += stats.requests || 0
      agentBreakdown[aid].tokens += (stats.inputTokens||0) + (stats.outputTokens||0)
    }
  }

  // Task stats
  const taskStats = {
    total: tasks.tasks.length,
    completed: tasks.tasks.filter(t => t.status === 'done').length,
    inProgress: tasks.tasks.filter(t => t.status === 'inprogress').length,
    todo: tasks.tasks.filter(t => t.status === 'todo').length
  }

  // Pipeline stats
  const pipeStats = {
    totalDeals: pipeline?.deals?.length || 0,
    totalValue: (pipeline?.deals || []).reduce((s,d) => s + (d.value||0), 0),
    wonDeals: (pipeline?.deals || []).filter(d => d.stage === 'won').length
  }

  const report = {
    id: loadReports().nextId,
    type: type || 'weekly',
    period: weekKey,
    generatedAt: now.toISOString(),
    summary: {
      requests: weekRequests,
      tokensIn: weekTokensIn,
      tokensOut: weekTokensOut,
      cost: weekCost,
      agentBreakdown,
      tasks: taskStats,
      pipeline: pipeStats,
      contacts: { total: contacts?.contacts?.length || 0 }
    }
  }

  const data = loadReports()
  report.id = data.nextId++
  data.reports.push(report)
  saveReports(data)

  addNotification(
    `Weekly Report Generated`,
    `Report for ${weekKey}: ${weekRequests} requests, $${weekCost.toFixed(2)} cost`,
    'info', 'reports'
  )

  return { ok: true, report }
})

// GET /api/reports — list reports
app.get('/api/reports', async () => {
  const data = loadReports()
  return { ok: true, reports: data.reports.slice().reverse() }
})

// GET /api/reports/:id — get specific report
app.get('/api/reports/:id', async (req) => {
  const data = loadReports()
  const report = data.reports.find(r => r.id === parseInt(req.params.id))
  if (!report) return { ok: false, error: 'Not found' }
  return { ok: true, report }
})
```

